if os.path.exists(file_path):
    with open(file_path, 'r') as f:
        nasdaq_capital_companies = json.load(f)

    print('__RESULT__:')
    print(json.dumps({
        'count': len(nasdaq_capital_companies),
        'first_five_symbols': [company['Symbol'] for company in nasdaq_capital_companies[:5]]
    }))
